UPDATE words SET example_en_2 = 'She is versatile enough to play in several positions.', example_ko_2 = '그녀는 여러 포지션에서 뛸 수 있을 만큼 다재다능해요.', example_en_3 = 'A versatile player is valuable in any team.', example_ko_3 = '다재다능한 선수는 어느 팀에서나 소중해요.', example_en_4 = 'His versatile playing style makes him hard to defend against.', example_ko_4 = '그의 다양한 플레이 스타일은 막기 어렵게 만들어요.', example_en_5 = 'Coaches prefer versatile players who can adapt quickly.', example_ko_5 = '코치들은 빠르게 적응할 수 있는 다재다능한 선수를 선호해요.' WHERE id = 'w_sports_B1_25';
UPDATE words SET example_en_2 = 'The team eliminated their rivals in the quarter-finals.', example_ko_2 = '팀은 8강에서 라이벌을 탈락시켰어요.', example_en_3 = 'She was eliminated in the early rounds of the competition.', example_ko_3 = '그녀는 대회 초반 라운드에서 탈락했어요.', example_en_4 = 'They need to win tonight to avoid being eliminated.', example_ko_4 = '탈락을 면하려면 오늘 밤 반드시 이겨야 해요.', example_en_5 = 'Losing two consecutive matches can eliminate a team from contention.', example_ko_5 = '2연패는 팀을 우승 경쟁에서 탈락시킬 수 있어요.' WHERE id = 'w_sports_B1_26';
