UPDATE words SET example_en_2 = 'The coach selected a squad of twenty-three players.', example_ko_2 = '코치가 23명의 선수단을 선발했어요.', example_en_3 = 'She was called up to the national squad for the first time.', example_ko_3 = '그녀는 처음으로 국가대표팀 선수단에 소집됐어요.', example_en_4 = 'The squad trained together for two weeks before the tournament.', example_ko_4 = '선수단은 토너먼트 전에 2주간 함께 훈련했어요.', example_en_5 = 'A strong squad gives the manager more options during games.', example_ko_5 = '강력한 선수단은 감독에게 경기 중 더 많은 선택지를 줘요.' WHERE id = 'w_sports_B1_28';
UPDATE words SET example_en_2 = 'The team kept possession for more than sixty per cent of the match.', example_ko_2 = '팀은 경기의 60% 이상 공을 점유했어요.', example_en_3 = 'Good possession football requires precise passing.', example_ko_3 = '좋은 점유 축구에는 정확한 패스가 필요해요.', example_en_4 = 'Losing possession in dangerous areas leads to goals against.', example_ko_4 = '위험 지역에서 공을 빼앗기면 실점으로 이어져요.', example_en_5 = 'She worked on retaining possession under pressure in training.', example_ko_5 = '그녀는 훈련에서 압박 상황에서도 공을 유지하는 연습을 했어요.' WHERE id = 'w_sports_B1_29';
UPDATE words SET example_en_2 = 'The rivalry between the two clubs goes back decades.', example_ko_2 = '두 클럽의 라이벌 관계는 수십 년 전으로 거슬러 올라가요.', example_en_3 = 'She pushed herself harder because of the rivalry.', example_ko_3 = '그녀는 라이벌 관계 때문에 더 열심히 노력했어요.', example_en_4 = 'The rivalry added extra intensity to the game.', example_ko_4 = '라이벌 관계가 경기에 더 강한 긴장감을 더해 줬어요.', example_en_5 = 'A healthy rivalry can bring out the best in both teams.', example_ko_5 = '건강한 경쟁 관계는 양팀의 최고의 실력을 끌어낼 수 있어요.' WHERE id = 'w_sports_B1_30';
